UPDATE TORDER_INFO_OR_DT
   SET 
		 ICKEY              = #{ickey}
		 ,ICUTKEY            = #{icutkey}
		 ,UOM                = #{uom}
		 ,ORIGIN_ICKEY 		 = CASE WHEN ICKEY != #{ickey} THEN ICKEY ELSE '' END
		 ,UPDATEDATE         = #{sysdate}
		 ,UPDATEURKEY        = #{surkey}
 WHERE 
 	   ORHDKEY = #{orhdkey}		
   AND ORDTKEY = #{ordtkey}

UPDATE TORDER_INFO_OR_HD
   SET WKSTATUS = #{wkstatus}
      ,IFSTATUS = #{ifstatus}
      ,PACKAGEORDERKEY = NULL
      ,AVINVSHORTFLAG = NULL
      ,UPDATEDATE         = #{sysdate}
	  ,UPDATEURKEY        = #{surkey}
 WHERE 
 	   ORHDKEY = #{orhdkey}

UPDATE TORDER_INFO_OR_DT
   SET WKSTATUS = #{wkstatus}
   	   ,AVINVSHORTFLAG = NULL
   	   ,UPDATEDATE         = #{sysdate}
	   ,UPDATEURKEY        = #{surkey}
 WHERE 
 	   ORHDKEY = #{orhdkey}

 	AND ORDTKEY = #{ordtkey}

UPDATE  TORDER_INFO_OR_HD
SET  WAYBILLNO = #{waybillno}
  ,UPDATEDATE         = #{sysdate}
  ,UPDATEURKEY        = #{surkey}
WHERE  OWKEY = #{owkey}
  AND  PACKAGEORDERKEY = #{packageorderkey}
